{
  "mode": "io",
  "tests": [
    {
      "name": "music_library_selection",
      "input": "select Artist – Song Title from Music Library",
      "output": "Audio players display original and infused songs; spectrographs shown.",
      "notes": "Validates the functionality of selecting a song from the library."
    },
    {
      "name": "upload_mp3_file",
      "input": "upload valid MP3 file",
      "output": "Audio players display original and infused songs; spectrographs shown.",
      "notes": "Checks the upload functionality for user-provided MP3 files."
    },
    {
      "name": "empty_music_library_selection",
      "input": "select from empty Music Library",
      "output": "Error message: 'No songs available in the library.'",
      "notes": "Tests the system's response to an empty music library."
    },
    {
      "name": "invalid_mp3_upload",
      "input": "upload non-MP3 file",
      "output": "Error message: 'Invalid file type. Please upload an MP3 file.'",
      "notes": "Ensures the system correctly handles invalid file uploads."
    },
    {
      "name": "apply_overlay_no_selection",
      "input": "click 'Apply Overlay' without selecting a song or uploading a file",
      "output": "Error message: 'Please select a song or upload an MP3 file.'",
      "notes": "Validates that the system prevents processing without input."
    },
    {
      "name": "large_mp3_file_upload",
      "input": "upload large MP3 file (e.g., 1GB)",
      "output": "Processing message displayed; audio players and spectrographs shown after processing.",
      "notes": "Tests the system's ability to handle large file uploads."
    },
    {
      "name": "apply_overlay_on_processed_song",
      "input": "select a song already infused and click 'Apply Overlay'",
      "output": "Audio players display original and infused songs; spectrographs shown.",
      "notes": "Checks if the system can process a song that has already been infused."
    },
    {
      "name": "view_overlay_data",
      "input": "click 'View Overlay Data' after processing",
      "output": "Spectrographs A and B displayed; metrics slide shown.",
      "notes": "Validates the display of overlay data after processing."
    }
  ],
  "assumptions": "The application is running in a suitable environment with Streamlit and necessary libraries installed.",
  "notes": "Ensure that all audio processing and visualization libraries are functional."
}
